def _svc_row(name: str, svc: str, label: str) -> str:
    """Build an HTML table row for a single service."""
    vm_h  = html.escape(name)
    svc_h = html.escape(svc)
    lbl_h = html.escape(label)
    return (
        f'<tr>'
        f'<td><a class="svc-link" href="/logs?vm={vm_h}&service={svc_h}">{lbl_h}</a></td>'
        f'<td>'
        f'<button class="svc-ctl" title="restart" data-vm="{vm_h}" data-svc="{svc_h}"'
        f' onclick="svcCtl(this.dataset.vm,this.dataset.svc,&apos;restart&apos;)">&#x21BA; Restart</button>'
        f' <button class="svc-ctl stop" title="stop" data-vm="{vm_h}" data-svc="{svc_h}"'
        f' onclick="svcCtl(this.dataset.vm,this.dataset.svc,&apos;stop&apos;)">&#x25A0; Stop</button>'
        f' <button class="svc-ctl" title="start" data-vm="{vm_h}" data-svc="{svc_h}"'
        f' onclick="svcCtl(this.dataset.vm,this.dataset.svc,&apos;start&apos;)">&#x25BA; Start</button>'
        f'</td>'
        f'</tr>'
    )

# ── VM cards ──────────────────────────────────────────────────────────────────

def vm_cards() -> str:
    refresh_oci_snapshots()
    fleet = load_json(TOOLS_DIR / "fleet.json") or {"vms": []}
    with _hb_lock:
        hbs = dict(_heartbeats)
    env      = _mgmt_env()
    ssh_user = env.get("OCI_SSH_USER", "ubuntu")

    cards = []
    for vm in fleet.get("vms", []):
        name       = vm.get("name", "")
        profile    = load_json(PROFILE_DIR / f"{name}.json") or {}
        instance   = profile.get("instance", {})
        state      = instance.get("lifecycle-state", "UNKNOWN")
        shape      = html.escape(instance.get("shape") or vm.get("shape", ""))
        public_ip  = profile.get("public_ip", "—")
        private_ip = profile.get("private_ip", "—")
        synced_at  = fmt_ago(profile["synced_at"]) if profile.get("synced_at") else "never"

        hb         = hbs.get(name, {})
        uptime_str = html.escape(hb.get("uptime", "—")) if hb else "—"
        hb_html    = ""
        uptime_cls = ""

        if name == "management":
            # Management is the heartbeat server — it never heartbeats itself.
            # Read uptime directly from /proc/uptime instead.
            try:
                secs = int(float(Path("/proc/uptime").read_text().split()[0]))
                d, rem = divmod(secs, 86400)
                h, rem = divmod(rem, 3600)
                m = rem // 60
                uptime_str = f"{d}d {h}h {m}m" if d else f"{h}h {m}m"
            except Exception:
                uptime_str = "—"
        elif hb:
            hb_html = f'<p><b>Heartbeat:</b> {html.escape(fmt_ago(hb.get("received_at", "")))}</p>'
        else:
            hb_html    = '<p class="warn-text"><b>Heartbeat:</b> not received yet</p>'
            uptime_cls = ' class="warn-text"'

        sc = state.lower().replace("/", "-")

        ssh_copy = ""
        if public_ip and public_ip != "—":
            raw_cmd  = f"ssh -i ~/.ssh/fleet.key {ssh_user}@{public_ip}"
            ssh_copy = (
                f'<button class="act-btn" onclick="copyText({json.dumps(raw_cmd)},this)">Copy SSH</button>'
            )

        role = vm.get("role", "")
        lottery_link = ""
        if role == "worker":
            lottery_link = (
                f'<a class="act-btn accent" '
                f'href="/logs?vm={html.escape(name)}&service=cloud-lab-a1-lottery">Lottery logs</a>'
            )

        services = _ROLE_SERVICES.get(role, []) + [
            (svc, label) for svc, label in vm.get("services", [])
            if svc not in {s for s, _ in _ROLE_SERVICES.get(role, [])}
        ]
        svc_html = ""
        if services:
            rows = "".join(_svc_row(name, svc, label) for svc, label in services)
            svc_html = (
                f'<div class="svc-section">'
                f'<p class="svc-label">Background services</p>'
                f'<table class="svc-table">'
                f'<thead><tr><th>Service</th><th>Actions</th></tr></thead>'
                f'<tbody>{rows}</tbody>'
                f'</table>'
                f'</div>'
            )

        notes = vm.get("notes", "")
        notes_html = f'<p class="notes">{html.escape(notes)}</p>' if notes else ""
        cards.append(
            f'<div class="card">'
            f'<div class="card-header">'
            f'<span class="vm-name">{html.escape(name)}</span>'
            f'<span class="badge {html.escape(sc)}">{html.escape(state)}</span>'
            f'</div>'
            f'{notes_html}'
            f'<p><b>Role:</b> {html.escape(role)}</p>'
            f'<p><b>Shape:</b> {shape}</p>'
            f'<p{uptime_cls}><b>Uptime:</b> {uptime_str}</p>'
            f'<p><b>Public IP:</b> {html.escape(public_ip)}</p>'
            f'<p><b>Private IP:</b> {html.escape(private_ip)}</p>'
            f'<p><b>OCI snapshot:</b> {html.escape(synced_at)}</p>'
            + (_mgmt_tls_html() if name == 'management' else '')
            + f'{hb_html}'
            f'<div class="card-actions">'
            f'<a class="act-btn" href="/stats?vm={html.escape(name)}">Live stats</a>'
            f'<a class="act-btn" href="/logs?vm={html.escape(name)}">Logs</a>'
            f'<a class="act-btn" href="/tools?vm={html.escape(name)}">Tools</a>'
            f'{lottery_link}'
            f'{ssh_copy}'
            f'</div>'
            f'{svc_html}'
            f'</div>'
        )
    return "\n".join(cards) if cards else "<p>No VMs defined in fleet.json.</p>"


