# ── queue page ────────────────────────────────────────────────────────────────

def queue_page(fleet_vms: list) -> bytes:
    title = f"{FLEET_NAME} — Job Queue"
    sections = []
    for vm in fleet_vms:
        jobs  = _read_vm_queue(vm)
        if not jobs:
            rows_html = '<p class="muted">No jobs.</p>'
        else:
            rows = []
            for j in jobs:
                st   = j.get("status", "?")
                out  = html.escape((j.get("output") or "")[:300])
                rows.append(
                    f'<tr>'
                    f'<td><span class="badge badge-{html.escape(st)}">{html.escape(st)}</span></td>'
                    f'<td>{html.escape(j.get("label","?"))}</td>'
                    f'<td class="muted">{html.escape(j.get("priority","?") and str(j["priority"]))}</td>'
                    f'<td class="muted">{html.escape(j.get("queued_at","")[:16])}</td>'
                    f'<td class="muted">{html.escape(j.get("completed_at","")[:16])}</td>'
                    f'<td><div class="q-output">{out}</div></td>'
                    f'</tr>'
                )
            rows_html = (
                '<table class="q-table"><thead><tr>'
                '<th>Status</th><th>Label</th><th>Pri</th>'
                '<th>Queued</th><th>Done</th><th>Output</th>'
                '</tr></thead><tbody>' + "".join(rows) + '</tbody></table>'
            )
        sections.append(
            f'<p class="section-title">{html.escape(vm)}</p>{rows_html}'
        )
    page = (
        _head(title)
        + _topbar("queue")
        + '<div class="content">'
        + "<p style='font-size:13px;color:var(--c-muted);margin:0 0 16px'>"
        + "On-demand job queue — tasks submitted via this console or the <code>/enqueue</code> API. "
        + "&#8220;No jobs&#8221; is normal on a fresh deployment until a job is submitted. "
        + "Background systemd services are not shown here &#8212; "
        + "those appear as service chips on the <a href='/'>Fleet</a> page."
        + "</p>"
        + "".join(sections)
        + '</div></body></html>'
    )
    return page.encode("utf-8")


# ── audit log page ─────────────────────────────────────────────────────────────

def audit_page() -> bytes:
    title   = f"{FLEET_NAME} — Audit Log"
    entries: list[dict] = []
    if AUDIT_LOG.exists():
        try:
            lines = AUDIT_LOG.read_text(encoding="utf-8").strip().splitlines()
            for line in lines[-200:]:
                try:
                    entries.append(json.loads(line))
                except Exception:
                    pass
        except Exception:
            pass
    entries.reverse()  # newest first
    if not entries:
        body = '<p class="muted">No audit entries yet.</p>'
    else:
        rows = []
        for e in entries:
            rows.append(
                f'<div class="audit-row">'
                f'<span class="audit-ts">{html.escape(e.get("ts","")[:16])}</span>'
                f'<span class="audit-who">{html.escape(e.get("ip","?"))}</span>'
                f'<span class="audit-act">{html.escape(e.get("action","?"))}</span>'
                f'<span class="audit-vm">{html.escape(e.get("vm","—"))}</span>'
                f'<span class="audit-det">{html.escape(e.get("details",""))}</span>'
                f'</div>'
            )
        body = "".join(rows)
    page = (
        _head(title)
        + _topbar("audit")
        + '<div class="content">'
        + '<p style="font-size:13px;color:var(--c-muted);margin:0 0 16px">'
        + 'Audit log &#8212; admin actions recorded by this console: script runs, service control, job submissions. '
        + 'Written to <code>~/cloud-lab/logs/audit.jsonl</code> on the management VM. '
        + 'Last 200 entries shown, newest first.'
        + '</p>'
        + body
        + '</div></body></html>'
    )
    return page.encode("utf-8")

# ── HTTP handler ──────────────────────────────────────────────────────────────

class Handler(BaseHTTPRequestHandler):
    def do_GET(self):
        parsed = urlparse(self.path)
        path   = parsed.path.rstrip("/") or "/"
        qs     = parse_qs(parsed.query)

        if path == "/favicon.ico":
            self._asset(200, base64.b64decode(FAVICON_B64), "image/x-icon"); return
        if path == "/apple-touch-icon.png":
            self._asset(200, base64.b64decode(APPLE_TOUCH_B64), "image/png"); return

        if path == "/login":
            self._html(200, login_page())
        elif path == "/logout":
            cookies = _parse_cookies(self.headers.get("Cookie", ""))
            sid = cookies.get(COOKIE_NAME, "")
            if sid:
                with _sessions_lock: _sessions.pop(sid, None)
            self.send_response(302)
            self.send_header("Location", "/login")
            self.send_header("Set-Cookie",
                f"{COOKIE_NAME}=; Path=/; HttpOnly; SameSite=Strict; Max-Age=0")
            self.end_headers()
        elif not _is_authed(self):
            self.send_response(302)
            self.send_header("Location", "/login"); self.end_headers()
        elif path == "/export":
            self._html(200, export_page())
        elif path == "/stats":
            fleet = load_json(TOOLS_DIR / "fleet.json") or {"vms": []}
            names = [v.get("name", "") for v in fleet.get("vms", []) if v.get("name")]
            vm    = (qs.get("vm") or ["management"])[0]
            if vm not in names: vm = "management"
            self._html(200, stats_page(vm, names))
        elif path == "/logs":
            fleet = load_json(TOOLS_DIR / "fleet.json") or {"vms": []}
            names = [v.get("name", "") for v in fleet.get("vms", []) if v.get("name")]
            vm    = (qs.get("vm")      or ["worker"])[0]
            svc   = (qs.get("service") or ["cloud-lab-a1-lottery"])[0]
            if vm not in names: vm = names[0] if names else "management"
            known = {s for s, _ in _LOG_SERVICES}
            if svc not in known: svc = "cloud-lab-a1-lottery"
            self._html(200, logs_page(vm, svc, names))
        elif path == "/tools":
            fleet = load_json(TOOLS_DIR / "fleet.json") or {"vms": []}
            names = [v.get("name", "") for v in fleet.get("vms", []) if v.get("name")]
            vm    = (qs.get("vm") or ["management"])[0]
            if vm not in names: vm = names[0] if names else "management"
            self._html(200, tools_page(vm, names))
        elif path == "/queue":
            fleet = load_json(TOOLS_DIR / "fleet.json") or {"vms": []}
            names = [v.get("name", "") for v in fleet.get("vms", []) if v.get("name")]
            self._html(200, queue_page(names))
        elif path == "/audit":
            self._html(200, audit_page())
        else:
            self._html(200, fleet_page())

    def _read_body(self, limit: int) -> bytes | None:
        try:
            length = int(self.headers.get("Content-Length", 0))
        except ValueError:
            return None
        if length < 0 or length > limit:
            return None
        return self.rfile.read(length)

    def _read_json_body(self, limit: int) -> dict | None:
        body = self._read_body(limit)
        if body is None:
            return None
        try:
            data = json.loads(body)
            return data if isinstance(data, dict) else None
        except Exception:
            return None

    def do_POST(self):
        length = int(self.headers.get("Content-Length", 0))
        body   = self.rfile.read(min(length, MAX_API_BODY)) if length else b""
        path   = urlparse(self.path).path.rstrip("/")

        if path == "/login":
            client_ip = self.client_address[0]
            if not _check_rate_limit(client_ip):
                self._html(429, login_page(error=True, locked=True)); return
            params   = parse_qs(body.decode("utf-8", errors="replace"))
            username = (params.get("username") or [""])[0]
            password = (params.get("password") or [""])[0]
            if username == USERNAME and _verify_password(password):
                _clear_fails(client_ip)
                sid = _create_session()
                self.send_response(302)
                self.send_header("Location", "/")
                self.send_header("Set-Cookie",
                    f"{COOKIE_NAME}={sid}; Path=/; HttpOnly; SameSite=Strict; "
                    f"Max-Age={SESSION_DURATION}")
                self.end_headers()
            else:
                _record_fail(client_ip)
                self._html(401, login_page(error=True))

        elif path == "/run-payload":
            if not _is_authed(self):
                self._respond(403, b'{"error":"not authenticated"}'); return
            try:
                data   = json.loads(body) if body else {}
                vm     = str(data.get("vm", "management"))
                script = str(data.get("script", ""))
                fleet  = load_json(TOOLS_DIR / "fleet.json") or {"vms": []}
                names  = {v.get("name") for v in fleet.get("vms", []) if v.get("name")}
                if vm not in names:
                    self._respond(400, b'{"error":"unknown vm"}'); return
                if not script.strip():
                    self._respond(400, b'{"error":"empty script"}'); return
                _write_audit("run-payload", vm, script[:120], self)
                exit_code, output = run_payload_on_vm(vm, script)
                result = json.dumps({"exit_code": exit_code, "output": output}).encode("utf-8")
                self.send_response(200)
                self.send_header("Content-Type", "application/json")
                self.end_headers(); self.wfile.write(result)
            except Exception as exc:
                err = json.dumps({"exit_code": 1, "output": f"Error: {exc}"}).encode("utf-8")
                self.send_response(500)
                self.send_header("Content-Type", "application/json")
                self.end_headers(); self.wfile.write(err)

        elif path == "/service-control":
            if not _is_authed(self):
                self._respond(403, b'{"error":"not authenticated"}'); return
            try:
                data    = json.loads(body) if body else {}
                vm      = str(data.get("vm", ""))
                service = str(data.get("service", ""))
                action  = str(data.get("action", ""))
                fleet   = load_json(TOOLS_DIR / "fleet.json") or {"vms": []}
                names   = {v.get("name") for v in fleet.get("vms", []) if v.get("name")}
                if vm not in names:
                    self._respond(400, b'{"error":"unknown vm"}'); return
                _write_audit("service-control", vm, f"{action} {service}", self)
                exit_code, output = _run_service_control(vm, service, action)
                result = json.dumps({"exit_code": exit_code, "output": output}).encode("utf-8")
                self.send_response(200)
                self.send_header("Content-Type", "application/json")
                self.end_headers(); self.wfile.write(result)
            except Exception as exc:
                err = json.dumps({"error": str(exc)}).encode("utf-8")
                self.send_response(500)
                self.send_header("Content-Type", "application/json")
                self.end_headers(); self.wfile.write(err)

        elif path == "/enqueue":
            if not _is_api_authed(self):
                self._respond(403, b'{"error":"not authenticated"}'); return
            try:
                data    = json.loads(body) if body else {}
                vm      = str(data.get("vm", "management"))
                label   = str(data.get("label", "API job"))
                command = str(data.get("command", ""))
                priority = int(data.get("priority", 5))
                if not command.strip():
                    self._respond(400, b'{"error":"command required"}'); return
                fleet   = load_json(TOOLS_DIR / "fleet.json") or {"vms": []}
                names   = {v.get("name") for v in fleet.get("vms", []) if v.get("name")}
                if vm not in names:
                    self._respond(400, b'{"error":"unknown vm"}'); return
                # For management: enqueue locally. Others: SSH enqueue.
                enqueue_cmd = (
                    f"python3 \"$CLOUD_LAB_DIR/payload/queue/queue_runner.py\" "
                    f"--enqueue --label {shlex.quote(label)} "
                    f"--command {shlex.quote(command)} --priority {priority}"
                )
                exit_code, output = run_payload_on_vm(vm, enqueue_cmd)
                _write_audit("enqueue", vm, f"label={label!r} priority={priority}", self)
                result = json.dumps({"exit_code": exit_code, "output": output}).encode("utf-8")
                self.send_response(200 if exit_code == 0 else 500)
                self.send_header("Content-Type", "application/json")
                self.end_headers(); self.wfile.write(result)
            except Exception as exc:
                err = json.dumps({"error": str(exc)}).encode("utf-8")
                self.send_response(500)
                self.send_header("Content-Type", "application/json")
                self.end_headers(); self.wfile.write(err)

        elif path == "/health":
            # Lightweight liveness probe for UptimeRobot / external monitors. No auth.
            body_out = json.dumps({"status": "ok", "ts": int(time.time())}).encode()
            self.send_response(200)
            self.send_header("Content-Type", "application/json")
            self.send_header("Content-Length", str(len(body_out)))
            self.end_headers()
            self.wfile.write(body_out)

        elif path == "/heartbeat":
            if not _is_heartbeat_authed(self):
                self._respond(403, b'{"ok":false}'); return
            data = self._read_json_body(MAX_HEARTBEAT_BODY)
            if data is None:
                self._respond(400, b'{"ok":false}'); return
            sender = str(data.get("vm_name") or data.get("vm") or "unknown")[:64]
            now    = datetime.now(timezone.utc).isoformat()
            with _hb_lock:
                existing = _heartbeats.get(sender, {})
                events   = list(existing.get("events", []))
                event    = data.get("event")
                if event:
                    events.append({"received_at": now, "event": str(event)[:200],
                                   "details": data.get("details", {})})
                    events = events[-50:]
                _heartbeats[sender] = {
                    "received_at": now, "uptime": str(data.get("uptime", "?"))[:80],
                    "extra": data, "events": events,
                }
            save_heartbeats()
            self._respond(200, b'{"ok":true}')
        else:
            self._respond(404, b"Not found")

    def _html(self, code: int, body: bytes) -> None:
        self.send_response(code)
        self.send_header("Content-Type", "text/html; charset=utf-8")
        self.end_headers(); self.wfile.write(body)

    def _asset(self, code: int, body: bytes, mime: str) -> None:
        self.send_response(code)
        self.send_header("Content-Type", mime)
        self.send_header("Cache-Control", "public, max-age=86400")
        self.end_headers(); self.wfile.write(body)

    def _respond(self, code: int, body: bytes) -> None:
        self.send_response(code); self.end_headers(); self.wfile.write(body)

    def log_message(self, format, *args): return


if __name__ == "__main__":
    load_heartbeats()
    print(f"[admin_console] Listening on {HOST}:{PORT}", flush=True)
    print(f"[admin_console] Fleet: {FLEET_NAME}", flush=True)
    print(f"[admin_console] Tools dir: {TOOLS_DIR}", flush=True)
    if PW_HASH:
        print(f"[admin_console] Password auth enabled. Username: {USERNAME}", flush=True)
    else:
        print("[admin_console] WARNING: ADMIN_PASSWORD_HASH not set — all logins will fail.", flush=True)
    ThreadingHTTPServer((HOST, PORT), Handler).serve_forever()
